import { useState, useRef, useEffect } from "react";

export default function App() {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const messagesEndRef = useRef(null);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const sendMessage = async () => {
  if (!input.trim()) return;

  const userMessage = { role: "user", content: input };
  const updatedMessages = [...messages, userMessage];
  setMessages(updatedMessages);
  setInput("");
  setLoading(true);

  try {
    const response = await fetch("https://mailbot-2e13.onrender.com/chat", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        messages: updatedMessages.map((m) => [m.role, m.content])
      }),
    });

    const data = await response.json();
    setMessages((prev) => [...prev, { role: "assistant", content: data.response }]);
  } catch (error) {
    setMessages((prev) => [...prev, { role: "assistant", content: "Something went wrong. Please try again." }]);
  }

  setLoading(false);
};

  return (
    <div style={{
      minHeight: "100vh",
      background: "#000000",
      display: "flex",
      flexDirection: "column",
      alignItems: "center",
      justifyContent: "center",
      fontFamily: "-apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif",
      padding: "20px"
    }}>

      {/* Logo and Title */}
      <div style={{
        display: "flex",
        alignItems: "center",
        gap: "16px",
        marginBottom: "32px"
      }}>
        <div style={{
          width: "64px",
          height: "64px",
          background: "linear-gradient(135deg, #2563eb, #1e40af)",
          borderRadius: "18px",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          fontSize: "34px"
        }}>✉️</div>
        <h1 style={{
          margin: 0,
          color: "white",
          fontSize: "42px",
          fontWeight: "700",
          letterSpacing: "-1px"
        }}>MailBot</h1>
      </div>

      {/* Suggestions - only show when no messages */}
      {messages.length === 0 && (
        <div style={{
          display: "flex",
          flexDirection: "column",
          gap: "8px",
          width: "100%",
          maxWidth: "620px",
          marginBottom: "16px"
        }}>
          <p style={{ margin: "0 0 8px 0", fontSize: "13px", color: "#555555", textAlign: "center" }}>
            Try one of these
          </p>
          {[
            "Draft an email to my manager asking for time off",
            "Write a follow-up email to a client",
            "Draft a professional apology email"
          ].map((suggestion, i) => (
            <button key={i} onClick={() => setInput(suggestion)} style={{
              background: "#111111",
              border: "1px solid #2a2a2a",
              borderRadius: "10px",
              padding: "10px 16px",
              fontSize: "13px",
              color: "#888888",
              cursor: "pointer",
              textAlign: "left"
            }}>{suggestion}</button>
          ))}
        </div>
      )}

      {/* Messages */}
      {messages.length > 0 && (
        <div style={{
          width: "100%",
          maxWidth: "620px",
          maxHeight: "55vh",
          overflowY: "auto",
          display: "flex",
          flexDirection: "column",
          gap: "16px",
          marginBottom: "16px",
          paddingRight: "4px"
        }}>
          {messages.map((msg, index) => (
            <div key={index} style={{
              display: "flex",
              justifyContent: msg.role === "user" ? "flex-end" : "flex-start",
              gap: "10px",
              alignItems: "flex-end"
            }}>
              {msg.role === "assistant" && (
                <div style={{
                  width: "32px", height: "32px",
                  background: "linear-gradient(135deg, #2563eb, #1e40af)",
                  borderRadius: "10px",
                  display: "flex", alignItems: "center", justifyContent: "center",
                  fontSize: "14px", flexShrink: 0
                }}>✉️</div>
              )}
              <div style={{
                maxWidth: "75%",
                padding: "12px 16px",
                borderRadius: msg.role === "user" ? "18px 18px 4px 18px" : "18px 18px 18px 4px",
                background: msg.role === "user" ? "linear-gradient(135deg, #2563eb, #1e40af)" : "#1e1e1e",
                color: "white",
                fontSize: "14px",
                lineHeight: "1.6",
                whiteSpace: "pre-wrap",
                border: msg.role === "assistant" ? "1px solid #2a2a2a" : "none"
              }}>
                {msg.content}
              </div>
            </div>
          ))}

          {loading && (
            <div style={{ display: "flex", gap: "10px", alignItems: "flex-end" }}>
              <div style={{
                width: "32px", height: "32px",
                background: "linear-gradient(135deg, #2563eb, #1e40af)",
                borderRadius: "10px",
                display: "flex", alignItems: "center", justifyContent: "center",
                fontSize: "14px"
              }}>✉️</div>
              <div style={{
                background: "#1e1e1e",
                border: "1px solid #2a2a2a",
                borderRadius: "18px 18px 18px 4px",
                padding: "12px 16px",
                display: "flex", gap: "4px", alignItems: "center"
              }}>
                {[0, 1, 2].map(i => (
                  <div key={i} style={{
                    width: "6px", height: "6px",
                    background: "#555555",
                    borderRadius: "50%",
                    animation: `bounce 1.2s ease-in-out ${i * 0.2}s infinite`
                  }}></div>
                ))}
              </div>
            </div>
          )}
          <div ref={messagesEndRef} />
        </div>
      )}

      {/* Input Box */}
      <div style={{
        width: "100%",
        maxWidth: "620px",
        display: "flex",
        gap: "10px",
        alignItems: "flex-end"
      }}>
        <textarea
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => {
            if (e.key === "Enter" && !e.shiftKey) {
              e.preventDefault();
              sendMessage();
            }
          }}
          placeholder="e.g. Draft an email to my manager asking for Friday off..."
          rows={1}
          style={{
            flex: 1,
            border: "1.5px solid #2a2a2a",
            borderRadius: "12px",
            padding: "14px 18px",
            fontSize: "14px",
            outline: "none",
            color: "white",
            background: "#111111",
            resize: "none",
            fontFamily: "-apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif",
            lineHeight: "1.5",
            maxHeight: "120px",
            overflowY: "auto"
          }}
        />
        <button
          onClick={sendMessage}
          disabled={loading}
          style={{
            background: loading ? "#333333" : "linear-gradient(135deg, #2563eb, #1e40af)",
            color: "white",
            border: "none",
            borderRadius: "12px",
            padding: "14px 20px",
            fontSize: "14px",
            fontWeight: "600",
            cursor: loading ? "not-allowed" : "pointer",
            whiteSpace: "nowrap"
          }}
        >
          Send ➤
        </button>
      </div>

      <style>{`
        @keyframes bounce {
          0%, 60%, 100% { transform: translateY(0); }
          30% { transform: translateY(-6px); }
        }
        textarea::placeholder { color: #444444; }
      `}</style>
    </div>
  );
}
